 */
static int extract_value(const char* config_line, const char* key, char* value, size_t value_size) {
    if (config_line == NULL || key == NULL || value == NULL || value_size == 0) {
        return 0;
    }

    // Find the key in the configuration line
    const char* key_pos = strstr(config_line, key);

    while (key_pos != NULL) {
        // Check if this is the start of the string or preceded by a comma
        if (key_pos == config_line || *(key_pos - 1) == ',') {
            // Check if followed by '='
            const char* equals_pos = key_pos + strlen(key);
            while (*equals_pos && isspace((unsigned char)*equals_pos)) {
                equals_pos++;
            }

            if (*equals_pos == '=') {
                // Found the key, extract the value
                const char* value_start = equals_pos + 1;

                // Skip leading whitespace
                while (*value_start && isspace((unsigned char)*value_start)) {
                    value_start++;
                }

                // Find the end of the value (comma or end of string)
                const char* value_end = value_start;
                while (*value_end && *value_end != ',') {
                    value_end++;
                }

                // Calculate value length
                size_t value_len = value_end - value_start;

                // Check buffer size
                if (value_len >= value_size) {
                    return 0; // Value too large for buffer
                }

                // Copy value to buffer
                strncpy(value, value_start, value_len);
                value[value_len] = '\0';

                // Trim whitespace from value
                trim_whitespace(value);

                return 1;
            }
        }

        // Search for next occurrence
        key_pos = strstr(key_pos + 1, key);
    }

    return 0;
}

int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config) {
    // Validate input parameters
    if (config_line == NULL || hw_config == NULL) {
        return -1;
    }

    // Check if config_line is empty
    if (*config_line == '\0') {
        return -1;
    }

    // Initialize the hardware config structure
    memset(hw_config, 0, sizeof(struct vm_hardware_config));

    // Flags to track which parameters were found
    int found_cpu = 0;
    int found_memory = 0;
    int found_disk = 0;
    int found_network = 0;

    char temp_value[512];

    // Extract cpu_model
    if (extract_value(config_line, "cpu_model", temp_value, sizeof(temp_value))) {
        if (strlen(temp_value) == 0 || strlen(temp_value) >= sizeof(hw_config->cpu_model)) {
