        }
        strncpy(hw_config->cpu_model, temp_value, sizeof(hw_config->cpu_model) - 1);
        hw_config->cpu_model[sizeof(hw_config->cpu_model) - 1] = '\0';
        found_cpu = 1;
    }

    // Extract memory_mb
    if (extract_value(config_line, "memory_mb", temp_value, sizeof(temp_value))) {
        if (strlen(temp_value) == 0) {
            return -1;
        }

        // Validate that the value contains only digits
        for (size_t i = 0; i < strlen(temp_value); i++) {
            if (!isdigit((unsigned char)temp_value[i])) {
                return -1;
            }
        }

        int memory_val = 0;
        if (sscanf(temp_value, "%d", &memory_val) == 1) {
            if (memory_val <= 0) {
                return -1;
            }
            hw_config->memory_mb = memory_val;
            found_memory = 1;
        }
    }

    // Extract disk_path
    if (extract_value(config_line, "disk_path", temp_value, sizeof(temp_value))) {
        if (strlen(temp_value) == 0 || strlen(temp_value) >= sizeof(hw_config->disk_path)) {
            return -1;
        }
        strncpy(hw_config->disk_path, temp_value, sizeof(hw_config->disk_path) - 1);
        hw_config->disk_path[sizeof(hw_config->disk_path) - 1] = '\0';
        found_disk = 1;
    }

    // Extract network_adapter
    if (extract_value(config_line, "network_adapter", temp_value, sizeof(temp_value))) {
        if (strlen(temp_value) == 0 || strlen(temp_value) >= sizeof(hw_config->network_adapter)) {
            return -1;
        }
        strncpy(hw_config->network_adapter, temp_value, sizeof(hw_config->network_adapter) - 1);
        hw_config->network_adapter[sizeof(hw_config->network_adapter) - 1] = '\0';
        found_network = 1;
    }

    // Check if all required parameters were found
    if (!found_cpu || !found_memory || !found_disk || !found_network) {
        return -1;
    }

    return 0;
}

